import './App.css';
import { useState, useEffect } from 'react';

function App() {

  const [loading, setLoading] = useState(true);
  const [students, setStudents] = useState([]);

  const data = [
    { id: 1, name: "Rahul", marks: 85 },
    { id: 2, name: "Anita", marks: 90 },
    { id: 3, name: "Kiran", marks: 78 }
  ];

  useEffect(() => {
    setTimeout(() => {
      setStudents(data);
      setLoading(false);
    }, 1000);
  }, []);

  return (
    <div className="App">
      <h1>Students Table</h1>

      {loading ? (
        <p>Loading...</p>
      ) : (
        <table border="1">
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Marks</th>
          </tr>
          {students.map((s) => (
            <tr key={s.id}>
              <td>{s.id}</td>
              <td>{s.name}</td>
              <td>{s.marks}</td>
            </tr>
          ))}
        </table>
      )}

    </div>
  );
}

export default App;
